      "path": "src/modules/projects/routes.js",
      "content": "const express = require('express');
const service = require('./service');
const { errorHandler } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  try {
    const project = await service.createProject(req.body);
    res.status(201).json({ project });
  } catch (error) {
    errorHandler(res, error);
  }
});

router.get('/', async (req, res) => {
  try {
    const projects = await service.getAllProjects();
    res.json({ projects });
  } catch (error) {
    errorHandler(res, error);
  }
});

router.get('/:projectId', async (req, res) => {
  try {
    const project = await service.getProjectById(req.params.projectId);
    res.json({ project });
  } catch (error) {
    errorHandler(res, error);
  }
});

router.use('/:projectId/members', require('./members/routes'));
router.use('/:projectId/tasks', require('./tasks/routes'));

module.exports = router;
