      "path": "src/modules/projects/members/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const projectsService = require('../service');

function addMember(projectId, { userId, role }) {
  if (!userId || !role) throw { code: 'invalid_input', message: 'UserId and role are required' };
  const project = projectsService.getProjectById(projectId);
  if (project.members[userId]) throw { code: 'duplicate_member', message: 'Member already exists in this project' };
  project.members[userId] = { userId, role };
  return project.members[userId];
}

function getAllMembers(projectId) {
  const project = projectsService.getProjectById(projectId);
  return project.members;
}

module.exports = { addMember, getAllMembers };
