      "path": "src/modules/projects/tasks/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const projectsService = require('../service');

function createTask(projectId, { title }) {
  if (!title) throw { code: 'invalid_input', message: 'Title is required' };
  const project = projectsService.getProjectById(projectId);
  const id = randomUUID();
  project.tasks[id] = { id, title, status: 'open' };
  return project.tasks[id];
}

function getAllTasks(projectId, status) {
  const project = projectsService.getProjectById(projectId);
  if (status) {
    return Object.values(project.tasks).filter(task => task.status === status);
  }
  return project.tasks;
}

function updateTask(projectId, taskId, { status }) {
  if (!['open', 'done'].includes(status)) throw { code: 'invalid_input', message: 'Invalid status' };
  const project = projectsService.getProjectById(projectId);
  const task = project.tasks[taskId];
  if (!task) throw { code: 'not_found', message: 'Task not found' };
  task.status = status;
  return task;
}

module.exports = { createTask, getAllTasks, updateTask };
